// CLX Pipeline Update — Phase 10: Calculate Statistics
// Counts leads at each status, calculates conversion rates, identifies stale leads

try {
  const allItems = $input.all();
  const leads = allItems.map(item => item.json);
  const now = new Date();

  // --- Count leads at each status ---
  const statusMap = {
    'New Lead': 0,
    'Researched': 0,
    'Scored': 0,
    'Signal Detected': 0,
    'Campaign Assigned': 0,
    'Outreach Ready': 0,
    'Contacted': 0,
    'Replied': 0,
    'Booking Sent': 0,
    'Booked': 0,
    'Closed Lost': 0,
    'Not Interested': 0
  };

  for (const lead of leads) {
    const status = lead.lead_status || '';
    if (statusMap.hasOwnProperty(status)) {
      statusMap[status]++;
    }
  }

  const totalLeads = leads.length;

  // --- Calculate conversion rates ---
  function rate(numerator, denominator) {
    if (denominator === 0) return 0;
    return Math.round((numerator / denominator) * 10000) / 100;
  }

  // Cumulative: leads that passed through each stage
  const passedResearch = totalLeads - statusMap['New Lead'];
  const passedScore = passedResearch - statusMap['Researched'];
  const passedOutreach = passedScore - statusMap['Scored'] - statusMap['Signal Detected'] - statusMap['Campaign Assigned'] - statusMap['Outreach Ready'];
  const passedReply = statusMap['Replied'] + statusMap['Booking Sent'] + statusMap['Booked'];
  const passedBooking = statusMap['Booking Sent'] + statusMap['Booked'];

  const importToResearchRate = rate(passedResearch, totalLeads);
  const researchToScoreRate = rate(passedScore, passedResearch || 1);
  const scoreToOutreachRate = rate(statusMap['Contacted'] + passedReply + statusMap['Closed Lost'], passedScore || 1);
  const outreachToReplyRate = rate(passedReply, statusMap['Contacted'] + passedReply + statusMap['Closed Lost'] || 1);
  const replyToBookingRate = rate(passedBooking, passedReply || 1);
  const conversionRateOverall = rate(statusMap['Booked'], totalLeads);

  // --- Identify stale leads ---
  const staleThresholds = {
    'New Lead': 2 * 60 * 60 * 1000,
    'Researched': 2 * 60 * 60 * 1000,
    'Scored': 2 * 60 * 60 * 1000,
    'Campaign Assigned': 2 * 60 * 60 * 1000,
    'Outreach Ready': 24 * 60 * 60 * 1000,
    'Contacted': 30 * 24 * 60 * 60 * 1000
  };

  const staleLeads = [];
  for (const lead of leads) {
    const status = lead.lead_status || '';
    const threshold = staleThresholds[status];
    if (threshold) {
      const updatedAt = new Date(lead.updated_at);
      const age = now.getTime() - updatedAt.getTime();
      if (age > threshold) {
        const hoursStale = Math.round(age / (60 * 60 * 1000));
        let thresholdLabel = '';
        if (threshold <= 2 * 60 * 60 * 1000) {
          thresholdLabel = '2 hours';
        } else if (threshold <= 24 * 60 * 60 * 1000) {
          thresholdLabel = '24 hours';
        } else {
          thresholdLabel = '30 days';
        }
        staleLeads.push({
          id: lead.id,
          lead_status: status,
          stale_reason: 'Stuck at ' + status + ' for ' + hoursStale + ' hours (threshold: ' + thresholdLabel + ')',
          stale_detected_at: now.toISOString()
        });
      }
    }
  }

  // --- Build stats object ---
  const stats = {
    snapshot_date: now.toISOString().split('T')[0],
    total_leads: totalLeads,
    new_lead_count: statusMap['New Lead'],
    researched_count: statusMap['Researched'],
    scored_count: statusMap['Scored'],
    signal_detected_count: statusMap['Signal Detected'],
    campaign_assigned_count: statusMap['Campaign Assigned'],
    outreach_ready_count: statusMap['Outreach Ready'],
    contacted_count: statusMap['Contacted'],
    replied_count: statusMap['Replied'],
    booking_sent_count: statusMap['Booking Sent'],
    booked_count: statusMap['Booked'],
    closed_lost_count: statusMap['Closed Lost'],
    not_interested_count: statusMap['Not Interested'],
    import_to_research_rate: importToResearchRate,
    research_to_score_rate: researchToScoreRate,
    score_to_outreach_rate: scoreToOutreachRate,
    outreach_to_reply_rate: outreachToReplyRate,
    reply_to_booking_rate: replyToBookingRate,
    conversion_rate_overall: conversionRateOverall
  };

  return {
    json: {
      stats: stats,
      stale_leads: staleLeads,
      stale_count: staleLeads.length
    }
  };
} catch (error) {
  return {
    json: {
      stats: null,
      stale_leads: [],
      stale_count: 0,
      error: error.message
    }
  };
}

// CLX Pipeline Update v2 — Prep Update Stale
// Marks a lead as stale with a reason string.

const item = $input.item.json;
const now = new Date().toISOString();

const body = {
  p_lead_id: item.id,
  p_fields: {
    is_stale: true,
    stale_reason: 'Stuck at ' + item.lead_status + ' since ' + item.updated_at,
    stale_detected_at: now
  }
};

console.log('PREP UPDATE:', JSON.stringify({ lead_id: item.id, status: item.lead_status, path: 'stale' }));

return { json: { ...item, rpc_body: JSON.stringify(body) } };
